import java.io.*;
import java.nio.charset.StandardCharsets;

public class SecureDeserializationExample {

    public static void main(String[] args) {
        try {
            String userInput = "serializedObject"; // Assume this is user-provided input
            byte[] serializedData = userInput.getBytes(StandardCharsets.ISO_8859_1);

            ByteArrayInputStream bais = new ByteArrayInputStream(serializedData);
            ObjectInputStream ois = new ObjectInputStream(bais) {
                @Override
                protected Class<?> resolveClass(ObjectStreamClass desc) throws IOException, ClassNotFoundException {
                    if (!desc.getName().startsWith("java")) {
                        throw new SecurityException("Unauthorized deserialization attempt");
                    }
                    return super.resolveClass(desc);
                }
            };

            Object obj = ois.readObject(); // Deserializing user-provided data

            System.out.println("Deserialized object: " + obj.toString());
        } catch (IOException | ClassNotFoundException | SecurityException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Insecure Deserialization
